import{_ as e,o as l,c as t,ai as i}from"./chunks/framework.ampVZV4B.js";const g=JSON.parse('{"title":"部署工具","description":"","frontmatter":{},"headers":[],"relativePath":"open-source/deployment-tools.md","filePath":"open-source/deployment-tools.md"}'),a={name:"open-source/deployment-tools.md"};function o(n,r,h,s,u,p){return l(),t("div",null,[...r[0]||(r[0]=[i('<h1 id="部署工具" tabindex="-1">部署工具 <a class="header-anchor" href="#部署工具" aria-label="Permalink to “部署工具”">​</a></h1><p>本页面精选了应用部署相关的开源工具，包括容器化、编排、服务网格等。</p><h2 id="容器化平台" tabindex="-1">容器化平台 <a class="header-anchor" href="#容器化平台" aria-label="Permalink to “容器化平台”">​</a></h2><h3 id="docker" tabindex="-1">Docker <a class="header-anchor" href="#docker" aria-label="Permalink to “Docker”">​</a></h3><ul><li><p><strong>Docker Engine</strong>：容器运行时</p><ul><li>GitHub: <a href="https://github.com/docker/docker" target="_blank" rel="noreferrer">https://github.com/docker/docker</a></li><li>功能: 容器创建、管理</li></ul></li><li><p><strong>Docker Compose</strong>：多容器编排</p><ul><li>GitHub: <a href="https://github.com/docker/compose" target="_blank" rel="noreferrer">https://github.com/docker/compose</a></li><li>功能: 定义多容器应用</li></ul></li><li><p><strong>Docker Swarm</strong>：Docker原生集群</p><ul><li>GitHub: <a href="https://github.com/docker/swarm" target="_blank" rel="noreferrer">https://github.com/docker/swarm</a></li><li>功能: 容器集群管理</li></ul></li></ul><h3 id="podman" tabindex="-1">Podman <a class="header-anchor" href="#podman" aria-label="Permalink to “Podman”">​</a></h3><ul><li><p><strong>Podman</strong>：无守护进程容器工具</p><ul><li>GitHub: <a href="https://github.com/containers/podman" target="_blank" rel="noreferrer">https://github.com/containers/podman</a></li><li>特点: 无需守护进程、rootless</li></ul></li><li><p><strong>Buildah</strong>：容器镜像构建工具</p><ul><li>GitHub: <a href="https://github.com/containers/buildah" target="_blank" rel="noreferrer">https://github.com/containers/buildah</a></li><li>功能: 脚本化镜像构建</li></ul></li></ul><h2 id="容器编排" tabindex="-1">容器编排 <a class="header-anchor" href="#容器编排" aria-label="Permalink to “容器编排”">​</a></h2><h3 id="kubernetes" tabindex="-1">Kubernetes <a class="header-anchor" href="#kubernetes" aria-label="Permalink to “Kubernetes”">​</a></h3><ul><li><p><strong>Kubernetes</strong>：容器编排平台</p><ul><li>GitHub: <a href="https://github.com/kubernetes/kubernetes" target="_blank" rel="noreferrer">https://github.com/kubernetes/kubernetes</a></li><li>功能: 自动化部署、扩展、管理</li></ul></li><li><p><strong>k3s</strong>：轻量级Kubernetes</p><ul><li>GitHub: <a href="https://github.com/k3s-io/k3s" target="_blank" rel="noreferrer">https://github.com/k3s-io/k3s</a></li><li>特点: 简化安装、资源占用少</li></ul></li><li><p><strong>minikube</strong>：本地Kubernetes环境</p><ul><li>GitHub: <a href="https://github.com/kubernetes/minikube" target="_blank" rel="noreferrer">https://github.com/kubernetes/minikube</a></li><li>功能: 本地开发测试</li></ul></li></ul><h3 id="其他编排工具" tabindex="-1">其他编排工具 <a class="header-anchor" href="#其他编排工具" aria-label="Permalink to “其他编排工具”">​</a></h3><ul><li><p><strong>Nomad</strong>：HashiCorp工作负载编排</p><ul><li>GitHub: <a href="https://github.com/hashicorp/nomad" target="_blank" rel="noreferrer">https://github.com/hashicorp/nomad</a></li><li>功能: 容器、虚拟机编排</li></ul></li><li><p><strong>Docker Swarm</strong>：Docker原生编排</p><ul><li>GitHub: <a href="https://github.com/docker/swarm" target="_blank" rel="noreferrer">https://github.com/docker/swarm</a></li><li>功能: 简单容器编排</li></ul></li></ul><h2 id="服务网格" tabindex="-1">服务网格 <a class="header-anchor" href="#服务网格" aria-label="Permalink to “服务网格”">​</a></h2><ul><li><p><strong>Istio</strong>：服务网格平台</p><ul><li>GitHub: <a href="https://github.com/istio/istio" target="_blank" rel="noreferrer">https://github.com/istio/istio</a></li><li>功能: 流量管理、安全、可观测性</li></ul></li><li><p><strong>Linkerd</strong>：轻量级服务网格</p><ul><li>GitHub: <a href="https://github.com/linkerd/linkerd2" target="_blank" rel="noreferrer">https://github.com/linkerd/linkerd2</a></li><li>特点: 简单、安全、资源效率</li></ul></li><li><p><strong>Consul</strong>：服务发现和配置</p><ul><li>GitHub: <a href="https://github.com/hashicorp/consul" target="_blank" rel="noreferrer">https://github.com/hashicorp/consul</a></li><li>功能: 服务网格、配置管理</li></ul></li></ul><h2 id="云原生工具" tabindex="-1">云原生工具 <a class="header-anchor" href="#云原生工具" aria-label="Permalink to “云原生工具”">​</a></h2><h3 id="cncf-项目" tabindex="-1">CNCF 项目 <a class="header-anchor" href="#cncf-项目" aria-label="Permalink to “CNCF 项目”">​</a></h3><ul><li><p><strong>Helm</strong>：Kubernetes包管理器</p><ul><li>GitHub: <a href="https://github.com/helm/helm" target="_blank" rel="noreferrer">https://github.com/helm/helm</a></li><li>功能: 应用打包、部署</li></ul></li><li><p><strong>etcd</strong>：分布式键值存储</p><ul><li>GitHub: <a href="https://github.com/etcd-io/etcd" target="_blank" rel="noreferrer">https://github.com/etcd-io/etcd</a></li><li>功能: 配置存储、服务发现</li></ul></li><li><p><strong>CoreDNS</strong>：DNS服务器</p><ul><li>GitHub: <a href="https://github.com/coredns/coredns" target="_blank" rel="noreferrer">https://github.com/coredns/coredns</a></li><li>功能: 服务发现、DNS解析</li></ul></li></ul><h3 id="存储" tabindex="-1">存储 <a class="header-anchor" href="#存储" aria-label="Permalink to “存储”">​</a></h3><ul><li><p><strong>Rook</strong>：云原生存储编排</p><ul><li>GitHub: <a href="https://github.com/rook/rook" target="_blank" rel="noreferrer">https://github.com/rook/rook</a></li><li>功能: Ceph、NFS存储</li></ul></li><li><p><strong>Longhorn</strong>：云原生分布式块存储</p><ul><li>GitHub: <a href="https://github.com/longhorn/longhorn" target="_blank" rel="noreferrer">https://github.com/longhorn/longhorn</a></li><li>特点: 简单、可靠</li></ul></li></ul><h2 id="ci-cd-工具" tabindex="-1">CI/CD 工具 <a class="header-anchor" href="#ci-cd-工具" aria-label="Permalink to “CI/CD 工具”">​</a></h2><h3 id="jenkins" tabindex="-1">Jenkins <a class="header-anchor" href="#jenkins" aria-label="Permalink to “Jenkins”">​</a></h3><ul><li><p><strong>Jenkins</strong>：自动化服务器</p><ul><li>GitHub: <a href="https://github.com/jenkinsci/jenkins" target="_blank" rel="noreferrer">https://github.com/jenkinsci/jenkins</a></li><li>功能: 持续集成、部署</li></ul></li><li><p><strong>Jenkins X</strong>：云原生CI/CD</p><ul><li>GitHub: <a href="https://github.com/jenkins-x/jx" target="_blank" rel="noreferrer">https://github.com/jenkins-x/jx</a></li><li>功能: GitOps、自动化</li></ul></li></ul><h3 id="gitops" tabindex="-1">GitOps <a class="header-anchor" href="#gitops" aria-label="Permalink to “GitOps”">​</a></h3><ul><li><p><strong>ArgoCD</strong>：GitOps持续交付</p><ul><li>GitHub: <a href="https://github.com/argoproj/argo-cd" target="_blank" rel="noreferrer">https://github.com/argoproj/argo-cd</a></li><li>功能: 声明式部署</li></ul></li><li><p><strong>Flux</strong>：GitOps工具包</p><ul><li>GitHub: <a href="https://github.com/fluxcd/flux2" target="_blank" rel="noreferrer">https://github.com/fluxcd/flux2</a></li><li>功能: 持续部署</li></ul></li></ul><h3 id="其他ci-cd" tabindex="-1">其他CI/CD <a class="header-anchor" href="#其他ci-cd" aria-label="Permalink to “其他CI/CD”">​</a></h3><ul><li><p><strong>Drone</strong>：容器原生CI/CD</p><ul><li>GitHub: <a href="https://github.com/harness/drone" target="_blank" rel="noreferrer">https://github.com/harness/drone</a></li><li>特点: 轻量级、Docker原生</li></ul></li><li><p><strong>Tekton</strong>：云原生CI/CD</p><ul><li>GitHub: <a href="https://github.com/tektoncd/pipeline" target="_blank" rel="noreferrer">https://github.com/tektoncd/pipeline</a></li><li>功能: Kubernetes原生管道</li></ul></li></ul><h2 id="配置管理" tabindex="-1">配置管理 <a class="header-anchor" href="#配置管理" aria-label="Permalink to “配置管理”">​</a></h2><ul><li><p><strong>Ansible</strong>：自动化配置管理</p><ul><li>GitHub: <a href="https://github.com/ansible/ansible" target="_blank" rel="noreferrer">https://github.com/ansible/ansible</a></li><li>功能: 自动化部署、配置</li></ul></li><li><p><strong>Puppet</strong>：配置管理工具</p><ul><li>GitHub: <a href="https://github.com/puppetlabs/puppet" target="_blank" rel="noreferrer">https://github.com/puppetlabs/puppet</a></li><li>功能: 基础设施即代码</li></ul></li><li><p><strong>Chef</strong>：自动化平台</p><ul><li>GitHub: <a href="https://github.com/chef/chef" target="_blank" rel="noreferrer">https://github.com/chef/chef</a></li><li>功能: 基础设施自动化</li></ul></li></ul><h2 id="监控与可观测性" tabindex="-1">监控与可观测性 <a class="header-anchor" href="#监控与可观测性" aria-label="Permalink to “监控与可观测性”">​</a></h2><h3 id="prometheus-生态" tabindex="-1">Prometheus 生态 <a class="header-anchor" href="#prometheus-生态" aria-label="Permalink to “Prometheus 生态”">​</a></h3><ul><li><p><strong>Prometheus</strong>：监控系统</p><ul><li>GitHub: <a href="https://github.com/prometheus/prometheus" target="_blank" rel="noreferrer">https://github.com/prometheus/prometheus</a></li><li>功能: 指标收集、告警</li></ul></li><li><p><strong>Alertmanager</strong>：告警管理</p><ul><li>GitHub: <a href="https://github.com/prometheus/alertmanager" target="_blank" rel="noreferrer">https://github.com/prometheus/alertmanager</a></li><li>功能: 告警路由、分组</li></ul></li><li><p><strong>Node Exporter</strong>：系统指标导出</p><ul><li>GitHub: <a href="https://github.com/prometheus/node_exporter" target="_blank" rel="noreferrer">https://github.com/prometheus/node_exporter</a></li><li>功能: 系统监控</li></ul></li></ul><h3 id="可视化" tabindex="-1">可视化 <a class="header-anchor" href="#可视化" aria-label="Permalink to “可视化”">​</a></h3><ul><li><p><strong>Grafana</strong>：仪表板平台</p><ul><li>GitHub: <a href="https://github.com/grafana/grafana" target="_blank" rel="noreferrer">https://github.com/grafana/grafana</a></li><li>功能: 数据可视化</li></ul></li><li><p><strong>Kibana</strong>：ELK可视化</p><ul><li>GitHub: <a href="https://github.com/elastic/kibana" target="_blank" rel="noreferrer">https://github.com/elastic/kibana</a></li><li>功能: 日志可视化</li></ul></li></ul><h3 id="分布式追踪" tabindex="-1">分布式追踪 <a class="header-anchor" href="#分布式追踪" aria-label="Permalink to “分布式追踪”">​</a></h3><ul><li><p><strong>Jaeger</strong>：分布式追踪</p><ul><li>GitHub: <a href="https://github.com/jaegertracing/jaeger" target="_blank" rel="noreferrer">https://github.com/jaegertracing/jaeger</a></li><li>功能: 请求追踪、性能分析</li></ul></li><li><p><strong>Zipkin</strong>：分布式追踪</p><ul><li>GitHub: <a href="https://github.com/openzipkin/zipkin" target="_blank" rel="noreferrer">https://github.com/openzipkin/zipkin</a></li><li>特点: 轻量级</li></ul></li></ul><h2 id="服务发现" tabindex="-1">服务发现 <a class="header-anchor" href="#服务发现" aria-label="Permalink to “服务发现”">​</a></h2><ul><li><p><strong>Consul</strong>：服务发现和配置</p><ul><li>GitHub: <a href="https://github.com/hashicorp/consul" target="_blank" rel="noreferrer">https://github.com/hashicorp/consul</a></li><li>功能: 服务注册、健康检查</li></ul></li><li><p><strong>Eureka</strong>：Netflix服务发现</p><ul><li>GitHub: <a href="https://github.com/Netflix/eureka" target="_blank" rel="noreferrer">https://github.com/Netflix/eureka</a></li><li>功能: 微服务注册中心</li></ul></li><li><p><strong>Zookeeper</strong>：分布式协调服务</p><ul><li>GitHub: <a href="https://github.com/apache/zookeeper" target="_blank" rel="noreferrer">https://github.com/apache/zookeeper</a></li><li>功能: 配置管理、分布式锁</li></ul></li></ul><h2 id="api-网关" tabindex="-1">API 网关 <a class="header-anchor" href="#api-网关" aria-label="Permalink to “API 网关”">​</a></h2><ul><li><p><strong>Kong</strong>：云原生API网关</p><ul><li>GitHub: <a href="https://github.com/Kong/kong" target="_blank" rel="noreferrer">https://github.com/Kong/kong</a></li><li>功能: API管理、微服务网关</li></ul></li><li><p><strong>Traefik</strong>：云原生边缘路由器</p><ul><li>GitHub: <a href="https://github.com/traefik/traefik" target="_blank" rel="noreferrer">https://github.com/traefik/traefik</a></li><li>功能: 自动服务发现、负载均衡</li></ul></li><li><p><strong>NGINX</strong>：高性能Web服务器</p><ul><li>GitHub: <a href="https://github.com/nginx/nginx" target="_blank" rel="noreferrer">https://github.com/nginx/nginx</a></li><li>功能: 反向代理、负载均衡</li></ul></li></ul><h2 id="负载均衡" tabindex="-1">负载均衡 <a class="header-anchor" href="#负载均衡" aria-label="Permalink to “负载均衡”">​</a></h2><ul><li><p><strong>HAProxy</strong>：高可用负载均衡</p><ul><li>GitHub: <a href="https://github.com/haproxy/haproxy" target="_blank" rel="noreferrer">https://github.com/haproxy/haproxy</a></li><li>功能: TCP/HTTP负载均衡</li></ul></li><li><p><strong>Envoy</strong>：云原生代理</p><ul><li>GitHub: <a href="https://github.com/envoyproxy/envoy" target="_blank" rel="noreferrer">https://github.com/envoyproxy/envoy</a></li><li>功能: 服务代理、API网关</li></ul></li><li><p><strong>MetalLB</strong>：Kubernetes负载均衡</p><ul><li>GitHub: <a href="https://github.com/metallb/metallb" target="_blank" rel="noreferrer">https://github.com/metallb/metallb</a></li><li>功能: 裸机负载均衡</li></ul></li></ul><h2 id="安全工具" tabindex="-1">安全工具 <a class="header-anchor" href="#安全工具" aria-label="Permalink to “安全工具”">​</a></h2><h3 id="访问控制" tabindex="-1">访问控制 <a class="header-anchor" href="#访问控制" aria-label="Permalink to “访问控制”">​</a></h3><ul><li><p><strong>Keycloak</strong>：身份和访问管理</p><ul><li>GitHub: <a href="https://github.com/keycloak/keycloak" target="_blank" rel="noreferrer">https://github.com/keycloak/keycloak</a></li><li>功能: SSO、身份管理</li></ul></li><li><p><strong>OAuth2 Proxy</strong>：OAuth2反向代理</p><ul><li>GitHub: <a href="https://github.com/oauth2-proxy/oauth2-proxy" target="_blank" rel="noreferrer">https://github.com/oauth2-proxy/oauth2-proxy</a></li><li>功能: 身份验证代理</li></ul></li></ul><h3 id="网络安全" tabindex="-1">网络安全 <a class="header-anchor" href="#网络安全" aria-label="Permalink to “网络安全”">​</a></h3><ul><li><p><strong>Calico</strong>：云原生网络安全</p><ul><li>GitHub: <a href="https://github.com/projectcalico/calico" target="_blank" rel="noreferrer">https://github.com/projectcalico/calico</a></li><li>功能: 网络策略、安全</li></ul></li><li><p><strong>Cilium</strong>：eBPF网络安全</p><ul><li>GitHub: <a href="https://github.com/cilium/cilium" target="_blank" rel="noreferrer">https://github.com/cilium/cilium</a></li><li>功能: 网络可见性、安全策略</li></ul></li></ul><h2 id="备份与恢复" tabindex="-1">备份与恢复 <a class="header-anchor" href="#备份与恢复" aria-label="Permalink to “备份与恢复”">​</a></h2><ul><li><p><strong>Velero</strong>：Kubernetes备份恢复</p><ul><li>GitHub: <a href="https://github.com/vmware-tanzu/velero" target="_blank" rel="noreferrer">https://github.com/vmware-tanzu/velero</a></li><li>功能: 集群备份、灾难恢复</li></ul></li><li><p><strong>Restic</strong>：现代备份程序</p><ul><li>GitHub: <a href="https://github.com/restic/restic" target="_blank" rel="noreferrer">https://github.com/restic/restic</a></li><li>特点: 安全、快速、开源</li></ul></li><li><p><strong>Bacula</strong>：企业级备份</p><ul><li>GitHub: <a href="https://github.com/bacula-org/bacula" target="_blank" rel="noreferrer">https://github.com/bacula-org/bacula</a></li><li>功能: 网络备份、恢复</li></ul></li></ul><h2 id="应用运行时" tabindex="-1">应用运行时 <a class="header-anchor" href="#应用运行时" aria-label="Permalink to “应用运行时”">​</a></h2><h3 id="java" tabindex="-1">Java <a class="header-anchor" href="#java" aria-label="Permalink to “Java”">​</a></h3><ul><li><p><strong>OpenJDK</strong>：开源Java平台</p><ul><li>GitHub: <a href="https://github.com/openjdk/jdk" target="_blank" rel="noreferrer">https://github.com/openjdk/jdk</a></li><li>功能: Java运行时</li></ul></li><li><p><strong>GraalVM</strong>：高性能JDK</p><ul><li>GitHub: <a href="https://github.com/oracle/graal" target="_blank" rel="noreferrer">https://github.com/oracle/graal</a></li><li>功能: 多语言支持、AOT编译</li></ul></li></ul><h3 id="node-js" tabindex="-1">Node.js <a class="header-anchor" href="#node-js" aria-label="Permalink to “Node.js”">​</a></h3><ul><li><p><strong>Node.js</strong>：JavaScript运行时</p><ul><li>GitHub: <a href="https://github.com/nodejs/node" target="_blank" rel="noreferrer">https://github.com/nodejs/node</a></li><li>功能: 服务器端JavaScript</li></ul></li><li><p><strong>Deno</strong>：安全JavaScript运行时</p><ul><li>GitHub: <a href="https://github.com/denoland/deno" target="_blank" rel="noreferrer">https://github.com/denoland/deno</a></li><li>特点: 内置TypeScript、安全默认</li></ul></li></ul><h3 id="python" tabindex="-1">Python <a class="header-anchor" href="#python" aria-label="Permalink to “Python”">​</a></h3><ul><li><p><strong>CPython</strong>：Python参考实现</p><ul><li>GitHub: <a href="https://github.com/python/cpython" target="_blank" rel="noreferrer">https://github.com/python/cpython</a></li><li>功能: Python解释器</li></ul></li><li><p><strong>PyPy</strong>：高性能Python</p><ul><li>GitHub: <a href="https://github.com/pypy/pypy" target="_blank" rel="noreferrer">https://github.com/pypy/pypy</a></li><li>特点: JIT编译、内存效率</li></ul></li></ul>',55)])])}const c=e(a,[["render",o]]);export{g as __pageData,c as default};
